def check_expression(expression):
    # İlgili ifadeyi kontrol etmek için bir dizi oluşturalım
    stack = []

    # İfadeyi karakterler olarak ayırıyoruz
    characters = list(expression)

    # İfadeyi karakterler olarak dolaşıyoruz
    for char in characters:
        # Açılan parantez ise stack'e ekliyoruz
        if char == '(':
            stack.append(char)
        # Kapalı parantez ise stack'ten bir parantez çıkarıyoruz
        elif char == ')':
            # Stack boşsa veya çıkarılan parantez açılan parantez değilse dengesizdir
            if not stack or stack.pop() != '(':
                return False
        # Açılan ve kapalı kare parantezler için de aynı işlemleri yapıyoruz
        elif char == '[':
            stack.append(char)
        elif char == ']':
            if not stack or stack.pop() != '[':
                return False
        # Açılan ve kapalı küme parantezler için de aynı işlemleri yapıyoruz
        elif char == '{':
            stack.append(char)
        elif char == '}':
            if not stack or stack.pop() != '{':
                return False

    # İfadeyi kontrol ettikten sonra stack boş olmalıdır
    # Aksi takdirde dengesizdir
    return not stack
