    element_counts = {}

    # Liste elemanlarını birer birer gezerek her bir elemanın sayısını hesaplayalım
    for element in lst:
        # Eğer eleman zaten sözlükte ise sayısını arttıralım, yoksa yeni bir eleman ekleyelim
        if element in element_counts:
            element_counts[element] += 1
        else:
            element_counts[element] = 1

    # Tuple'deki her bir elemanın sayısını hesaplayalım
    tup_counts = {}
    for element in tup:
        # Eğer eleman zaten sözlükte ise sayısını arttıralım, yoksa yeni bir eleman ekleyelim
        if element in tup_counts:
            tup_counts[element] += 1
        else:
            tup_counts[element] = 1

    # Her bir elemanın listedeki ve tupledeki sayısını karşılaştırarak sonuçları bir sözlükte saklayalım
    result = {}
    for element in set(lst + tup):
        result[element] = (element_counts.get(element, 0), tup_counts.get(element, 0))

    return result

