def replace_max_specialchar(text, n):
    # Özel karakterler listesi
    special_chars = [' ', ',', '.']

    # Karakter sayımı
    char_count = {}
    for char in text:
        if char in special_chars:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1

    # En fazla kaç karakter değiştirilecek
    max_char = max(char_count.values())

    # En fazla kaç karakter değiştirilecekse
    if max_char <= n:
        # Tüm karakterleri değiştir
        for char in special_chars:
            text = text.replace(char, ':')
    else:
        # En fazla karakter sayısını değiştir
        for char in special_chars:
            if char_count[char] > n:
                text = text.replace(char, ':', n)
                break

    return text
```

