def is_Isomorphic(str1, str2):
    # İki dizi oluşturarak karakterlerin eşleniklerini tutacağız
    mapping1 = {}
    mapping2 = {}

    # İki dizi aynı uzunlukta ise ve karakterlerin eşleniklerini tuttukça, iki string birbirine eşlenik ise true dönecek
    if len(str1) != len(str2):
        return False

    for c1, c2 in zip(str1, str2):
        # Eğer mapping1'de c1 karakteri yoksa, c1 ile c2 karakterini mapping1'e ekleyeceğiz
        if c1 not in mapping1:
            mapping1[c1] = c2
        # Eğer mapping2'de c2 karakteri yoksa, c1 ile c2 karakterini mapping2'ye ekleyeceğiz
        if c2 not in mapping2:
            mapping2[c2] = c1
        # Eğer mapping1'de c1 karakterinin eşlenik c2 karakteri ile c2 karakterinin eşlenik c1 karakteri farklı ise, false dönecek
        if mapping1[c1] != c2 or mapping2[c2] != c1:
            return False

    # Eğer tüm karakterlerin eşleniklerini tuttuk ve eşlenik karakterler aynı ise, true dönecek
    return True
