def check_last(arr, p):
    # Son eleman olup olmadığını kontrol edelim
    if len(arr) == 0:
        return False

    # Son eleman olup olmadığını kontrol edelim
    last_element = arr[-1]

    # p kere 1 ekleyelim
    for _ in range(p):
        # Son eleman 1 artırdığımızda çift mi yoksa tek mi olduğunu kontrol edelim
        if (last_element + 1) % 2 == 0:
            # Son eleman çift ise
            last_element += 1
        else:
            # Son eleman tek ise
            last_element += 1

    # Son eleman çift mi yoksa tek mi olduğunu kontrol edelim
    if last_element % 2 == 0:
        return True
    else:
        return False
